					LDAP_SLIST_INSERT_HEAD(&pq->ltp_free_list, task,
						ltt_next.l);
					goto failed;
				}
			}
			/* there is another open thread, so this
			 * task will be handled eventually.
			 */
		}
	}
	ldap_pvt_thread_cond_signal(&pq->ltp_cond);

 done:
	ldap_pvt_thread_mutex_unlock(&pq->ltp_mutex);
	return(0);

 failed:
	ldap_pvt_thread_mutex_unlock(&pq->ltp_mutex);
	return(-1);
}

