		pool->ltp_max_pending = -pool->ltp_max_pending;

	ldap_pvt_thread_cond_broadcast(&pool->ltp_cond);
	ldap_pvt_thread_mutex_unlock(&pool->ltp_mutex);

	for (i=0; i<pool->ltp_numqs; i++) {
		pq = pool->ltp_wqs[i];
		ldap_pvt_thread_mutex_lock(&pq->ltp_mutex);
